---
import type { HTMLAttributes } from "astro/types"

interface Props extends HTMLAttributes<"div"> {
  defaultOpen?: boolean
  closeOnClickOutside?: boolean
  closeOnEscape?: boolean
  lockScroll?: boolean
}

const {
  class: className,
  defaultOpen,
  closeOnClickOutside,
  closeOnEscape,
  lockScroll,
  ...props
} = Astro.props

const booleanDataAttr = (value?: boolean) =>
  value === undefined ? undefined : value ? "" : "false"
---

<div
  data-slot="sheet"
  data-default-open={booleanDataAttr(defaultOpen)}
  data-close-on-click-outside={booleanDataAttr(closeOnClickOutside)}
  data-close-on-escape={booleanDataAttr(closeOnEscape)}
  data-lock-scroll={booleanDataAttr(lockScroll)}
  class={className}
  {...props}
>
  <slot />
</div>

<script>
  import {
    clearRootBinding,
    createDismissLayer,
    createModalStackItem,
    createPortalLifecycle,
    createPresenceLifecycle,
    emit,
    ensureId,
    focusElement,
    getDataBool,
    getPart,
    getParts,
    getRoots,
    hasRootBinding,
    linkLabelledBy,
    lockScroll,
    on,
    reuseRootBinding,
    setAria,
    setRootBinding,
    unlockScroll,
  } from "@data-slot/core"

  const ROOT_BINDING_KEY = "@fulldev-ui/sheet"
  const FOCUSABLE_SELECTOR =
    'a[href],button:not([disabled]),input:not([disabled]),select:not([disabled]),textarea:not([disabled]),[tabindex]:not([tabindex="-1"])'

  interface SheetOptions {
    defaultOpen?: boolean
    onOpenChange?: (open: boolean) => void
    closeOnClickOutside?: boolean
    closeOnEscape?: boolean
    lockScroll?: boolean
  }

  interface SheetController {
    open(): void
    close(): void
    toggle(): void
    readonly isOpen: boolean
    destroy(): void
    _handleKeydown?(event: KeyboardEvent): void
    _content?: HTMLElement
    _overlay?: HTMLElement
  }

  let activeSheetScrollLocks = 0
  let activeSheetScrollbarWidth = 0

  const ORIGINAL_RIGHT_STYLE_KEY = "sheetOriginalRight"
  const ORIGINAL_LEFT_STYLE_KEY = "sheetOriginalLeft"

  const getScrollbarWidth = () =>
    Math.max(0, window.innerWidth - document.documentElement.clientWidth)

  const preserveInlineOffsets = (element: HTMLElement) => {
    if (!(ORIGINAL_RIGHT_STYLE_KEY in element.dataset)) {
      element.dataset[ORIGINAL_RIGHT_STYLE_KEY] =
        element.style.getPropertyValue("right")
    }

    if (!(ORIGINAL_LEFT_STYLE_KEY in element.dataset)) {
      element.dataset[ORIGINAL_LEFT_STYLE_KEY] =
        element.style.getPropertyValue("left")
    }
  }

  const restoreInlineOffsets = (element: HTMLElement) => {
    const originalRight = element.dataset[ORIGINAL_RIGHT_STYLE_KEY]
    const originalLeft = element.dataset[ORIGINAL_LEFT_STYLE_KEY]

    if (originalRight !== undefined) {
      if (originalRight) {
        element.style.setProperty("right", originalRight)
      } else {
        element.style.removeProperty("right")
      }

      delete element.dataset[ORIGINAL_RIGHT_STYLE_KEY]
    }

    if (originalLeft !== undefined) {
      if (originalLeft) {
        element.style.setProperty("left", originalLeft)
      } else {
        element.style.removeProperty("left")
      }

      delete element.dataset[ORIGINAL_LEFT_STYLE_KEY]
    }
  }

  const setInlineEndOffset = (
    element: HTMLElement,
    direction: string,
    offset: string
  ) => {
    preserveInlineOffsets(element)

    if (direction === "rtl") {
      element.style.setProperty("left", offset)
      return
    }

    element.style.setProperty("right", offset)
  }

  const applySheetViewportCompensation = (
    overlay: HTMLElement,
    content: HTMLElement,
    scrollbarWidth: number
  ) => {
    const offset = scrollbarWidth > 0 ? `${scrollbarWidth * -1}px` : "0px"
    const direction = getComputedStyle(content).direction
    const side = content.dataset.side
    const alignsWithInlineEnd =
      side === "top" ||
      side === "bottom" ||
      (side === "right" && direction !== "rtl") ||
      (side === "left" && direction === "rtl")

    setInlineEndOffset(overlay, direction, offset)

    if (alignsWithInlineEnd) {
      setInlineEndOffset(content, direction, offset)
      return
    }

    restoreInlineOffsets(content)
  }

  const clearSheetViewportCompensation = (
    overlay: HTMLElement,
    content: HTMLElement
  ) => {
    restoreInlineOffsets(overlay)
    restoreInlineOffsets(content)
  }

  const createSheet = (
    root: Element,
    options: SheetOptions = {}
  ): SheetController => {
    const existingController = reuseRootBinding(
      root,
      ROOT_BINDING_KEY,
      "[@data-slot/sheet] createSheet() called more than once for the same root. Returning the existing controller. Destroy it before rebinding with new options."
    )

    if (existingController) {
      return existingController as SheetController
    }

    const defaultOpen =
      options.defaultOpen ?? getDataBool(root, "defaultOpen") ?? false
    const onOpenChange = options.onOpenChange
    const closeOnClickOutside =
      options.closeOnClickOutside ??
      getDataBool(root, "closeOnClickOutside") ??
      true
    const closeOnEscape =
      options.closeOnEscape ?? getDataBool(root, "closeOnEscape") ?? true
    const shouldLockScroll =
      options.lockScroll ?? getDataBool(root, "lockScroll") ?? true

    const triggers = getParts(root, "sheet-trigger") as HTMLElement[]
    const closeButtons = getParts(root, "sheet-close") as HTMLElement[]
    const portal = getPart(root, "sheet-portal") as HTMLElement | null
    const overlay = getPart(root, "sheet-overlay") as HTMLElement | null
    const content = getPart(root, "sheet-content") as HTMLElement | null
    const title = getPart(root, "sheet-title") as HTMLElement | null
    const description = getPart(root, "sheet-description") as HTMLElement | null

    if (!content) {
      throw new Error("Sheet requires sheet-content slot")
    }

    if (!overlay) {
      throw new Error("Sheet requires sheet-overlay slot")
    }

    let isDestroyed = false
    let isOpen = false
    let lastFocusedElement: Element | null = null
    const cleanupFns: Array<() => void> = []
    const portalLifecycle = portal
      ? createPortalLifecycle({
          content: portal,
          root,
        })
      : null
    let isScrollLocked = false
    let addedContentTabIndex = false
    let visibilitySequence = 0
    let pendingExitHides = 0
    let overlayExitSequence = 0
    let contentExitSequence = 0

    ensureId(content, "sheet-content")
    content.setAttribute("role", "dialog")
    setAria(content, "modal", true)
    linkLabelledBy(content, title, description)

    overlay.setAttribute("role", "presentation")
    overlay.setAttribute("aria-hidden", "true")
    overlay.tabIndex = -1

    triggers.forEach((trigger) => {
      trigger.setAttribute("aria-haspopup", "dialog")
      trigger.setAttribute("aria-controls", content.id)
      setAria(trigger, "expanded", false)
    })

    const ensureContentTabIndex = () => {
      if (content.hasAttribute("tabindex")) {
        return
      }

      content.tabIndex = -1
      addedContentTabIndex = true
    }

    const cleanupContentTabIndex = () => {
      if (!addedContentTabIndex) {
        return
      }

      content.removeAttribute("tabindex")
      addedContentTabIndex = false
    }

    const focusContent = () => {
      const autofocusTarget = content.querySelector<HTMLElement>("[autofocus]")

      if (autofocusTarget) {
        autofocusTarget.focus()
        return
      }

      const firstFocusableElement =
        content.querySelector<HTMLElement>(FOCUSABLE_SELECTOR)

      if (firstFocusableElement) {
        firstFocusableElement.focus()
        return
      }

      ensureContentTabIndex()
      content.focus()
    }

    const restoreFocus = () => {
      requestAnimationFrame(() => {
        if (
          lastFocusedElement &&
          document.contains(lastFocusedElement) &&
          typeof (lastFocusedElement as HTMLElement).focus === "function"
        ) {
          focusElement(lastFocusedElement as HTMLElement)
        } else {
          const firstAvailableTrigger = triggers.find((trigger) =>
            document.contains(trigger)
          )

          if (firstAvailableTrigger) {
            focusElement(firstAvailableTrigger)
          }
        }

        lastFocusedElement = null
      })
    }

    const setStateAttributes = (state: "open" | "closed") => {
      root.setAttribute("data-state", state)
      portal?.setAttribute("data-state", state)
      overlay.setAttribute("data-state", state)
      content.setAttribute("data-state", state)

      if (state === "open") {
        root.setAttribute("data-open", "")
        portal?.setAttribute("data-open", "")
        overlay.setAttribute("data-open", "")
        content.setAttribute("data-open", "")

        root.removeAttribute("data-closed")
        portal?.removeAttribute("data-closed")
        overlay.removeAttribute("data-closed")
        content.removeAttribute("data-closed")
        return
      }

      root.setAttribute("data-closed", "")
      portal?.setAttribute("data-closed", "")
      overlay.setAttribute("data-closed", "")
      content.setAttribute("data-closed", "")

      root.removeAttribute("data-open")
      portal?.removeAttribute("data-open")
      overlay.removeAttribute("data-open")
      content.removeAttribute("data-open")
    }

    const completeExit = (element: HTMLElement, sequence: number) => {
      if (isDestroyed || isOpen || sequence !== visibilitySequence) {
        return
      }

      element.hidden = true
      pendingExitHides = Math.max(0, pendingExitHides - 1)

      if (pendingExitHides === 0) {
        cleanupContentTabIndex()
        restoreFocus()
      }
    }

    const overlayPresence = createPresenceLifecycle({
      element: overlay,
      onExitComplete: () => completeExit(overlay, overlayExitSequence),
    })

    const contentPresence = createPresenceLifecycle({
      element: content,
      onExitComplete: () => completeExit(content, contentExitSequence),
    })

    const handleTabKeydown = (event: KeyboardEvent) => {
      if (event.key !== "Tab") {
        return
      }

      const focusableElements =
        content.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR)

      if (focusableElements.length === 0) {
        event.preventDefault()
        ensureContentTabIndex()
        content.focus()
        return
      }

      const firstFocusableElement = focusableElements[0]
      const lastFocusableElement =
        focusableElements[focusableElements.length - 1]
      const activeElement = document.activeElement

      if (!content.contains(activeElement)) {
        event.preventDefault()
        firstFocusableElement.focus()
        return
      }

      if (firstFocusableElement === lastFocusableElement) {
        event.preventDefault()
        return
      }

      if (event.shiftKey) {
        if (activeElement === firstFocusableElement) {
          event.preventDefault()
          lastFocusableElement.focus()
        }

        return
      }

      if (activeElement === lastFocusableElement) {
        event.preventDefault()
        firstFocusableElement.focus()
      }
    }

    const modalStack = createModalStackItem({
      content,
      overlay,
      onTabKeydown: handleTabKeydown,
      cssVarPrefix: "sheet",
    })

    const setOpen = (nextOpen: boolean, force = false) => {
      if (isOpen === nextOpen && !force) {
        return
      }

      visibilitySequence += 1

      if (nextOpen) {
        pendingExitHides = 0
        portalLifecycle?.mount()
        lastFocusedElement = document.activeElement
        modalStack.open()

        if (shouldLockScroll && !isScrollLocked) {
          const scrollbarWidth =
            activeSheetScrollLocks > 0
              ? activeSheetScrollbarWidth
              : getScrollbarWidth()

          lockScroll()
          activeSheetScrollbarWidth = scrollbarWidth
          activeSheetScrollLocks += 1
          isScrollLocked = true
        }

        applySheetViewportCompensation(
          overlay,
          content,
          activeSheetScrollbarWidth
        )
      } else {
        pendingExitHides = 2
        overlayExitSequence = visibilitySequence
        contentExitSequence = visibilitySequence
        modalStack.close()
        clearSheetViewportCompensation(overlay, content)

        if (isScrollLocked) {
          unlockScroll()
          activeSheetScrollLocks = Math.max(0, activeSheetScrollLocks - 1)
          if (activeSheetScrollLocks === 0) {
            activeSheetScrollbarWidth = 0
          }
          isScrollLocked = false
        }
      }

      isOpen = nextOpen

      triggers.forEach((trigger) => {
        setAria(trigger, "expanded", isOpen)
      })

      if (nextOpen) {
        overlay.hidden = false
        content.hidden = false
        setStateAttributes("open")
        overlayPresence.enter()
        contentPresence.enter()
        requestAnimationFrame(focusContent)
      } else {
        setStateAttributes("closed")
        overlayPresence.exit()
        contentPresence.exit()
      }

      emit(root, "sheet:change", { open: isOpen })
      onOpenChange?.(isOpen)
    }

    overlay.hidden = true
    content.hidden = true
    setStateAttributes("closed")

    triggers.forEach((trigger) => {
      cleanupFns.push(
        on(trigger, "click", () => {
          setOpen(!isOpen)
        })
      )
    })

    closeButtons.forEach((button) => {
      cleanupFns.push(
        on(button, "click", () => {
          setOpen(false)
        })
      )
    })

    if (closeOnClickOutside) {
      cleanupFns.push(
        on(overlay, "click", (event) => {
          if (event.button === 0 && event.target === overlay && isOpen) {
            setOpen(false)
          }
        })
      )
    }

    cleanupFns.push(
      createDismissLayer({
        root,
        isOpen: () => isOpen,
        onDismiss: () => setOpen(false),
        closeOnClickOutside: false,
        closeOnEscape,
      })
    )

    const controller: SheetController = {
      open: () => setOpen(true),
      close: () => setOpen(false),
      toggle: () => setOpen(!isOpen),
      get isOpen() {
        return isOpen
      },
      destroy: () => {
        isDestroyed = true
        modalStack.destroy()
        visibilitySequence += 1
        pendingExitHides = 0
        overlayPresence.cleanup()
        contentPresence.cleanup()
        isOpen = false
        setStateAttributes("closed")
        overlay.hidden = true
        content.hidden = true

        triggers.forEach((trigger) => {
          setAria(trigger, "expanded", false)
        })

        if (isScrollLocked) {
          unlockScroll()
          activeSheetScrollLocks = Math.max(0, activeSheetScrollLocks - 1)
          if (activeSheetScrollLocks === 0) {
            activeSheetScrollbarWidth = 0
          }
          isScrollLocked = false
        }

        clearSheetViewportCompensation(overlay, content)
        cleanupContentTabIndex()

        if (lastFocusedElement !== null) {
          restoreFocus()
        }

        cleanupFns.forEach((cleanup) => cleanup())
        cleanupFns.length = 0
        portalLifecycle?.cleanup()
        clearRootBinding(root, ROOT_BINDING_KEY, controller)
      },
      _handleKeydown: handleTabKeydown,
      _content: content,
      _overlay: overlay,
    }

    cleanupFns.push(
      on(root, "sheet:set", (event: Event) => {
        const customEvent = event as CustomEvent<{
          open?: boolean
          value?: boolean
        }>

        let nextOpen: boolean | undefined

        if (customEvent.detail?.open === undefined) {
          if (customEvent.detail?.value !== undefined) {
            nextOpen = customEvent.detail.value
          }
        } else {
          nextOpen = customEvent.detail.open
        }

        if (typeof nextOpen === "boolean") {
          setOpen(nextOpen)
        }
      })
    )

    setRootBinding(root, ROOT_BINDING_KEY, controller)

    if (defaultOpen) {
      setOpen(true, true)
    }

    return controller
  }

  const create = (scope: ParentNode = document) => {
    const controllers: SheetController[] = []

    for (const root of getRoots(scope, "sheet")) {
      if (!hasRootBinding(root, ROOT_BINDING_KEY)) {
        controllers.push(createSheet(root))
      }
    }

    return controllers
  }

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"
import { X as XIcon } from "@lucide/astro"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"

const sheetContentVariants = cva(
  "bg-popover text-popover-foreground fixed flex flex-col gap-4 bg-clip-padding text-sm shadow-lg transition duration-200 ease-in-out outline-none data-[ending-style]:opacity-0 data-[starting-style]:opacity-0",
  {
    variants: {
      side: {
        top: [
          "inset-x-0 top-0 h-auto border-b",
          "data-[ending-style]:-translate-y-10 data-[starting-style]:-translate-y-10",
        ],
        right: [
          "inset-y-0 right-0 h-full w-3/4 border-l sm:max-w-sm",
          "data-[ending-style]:translate-x-10 data-[starting-style]:translate-x-10",
        ],
        bottom: [
          "inset-x-0 bottom-0 h-auto border-t",
          "data-[ending-style]:translate-y-10 data-[starting-style]:translate-y-10",
        ],
        left: [
          "inset-y-0 left-0 h-full w-3/4 border-r sm:max-w-sm",
          "data-[ending-style]:-translate-x-10 data-[starting-style]:-translate-x-10",
        ],
      },
    },
    defaultVariants: {
      side: "right",
    },
  }
)

interface Props
  extends HTMLAttributes<"div">, VariantProps<typeof sheetContentVariants> {
  showCloseButton?: boolean
}

const {
  class: className,
  side = "right",
  showCloseButton = true,
  style,
  ...props
} = Astro.props
---

<div data-slot="sheet-portal">
  <div
    data-slot="sheet-overlay"
    hidden
    class="fixed inset-0 bg-black/10 transition-opacity duration-150 data-[ending-style]:opacity-0 data-[starting-style]:opacity-0 supports-backdrop-filter:backdrop-blur-xs"
    style="z-index: calc(var(--sheet-overlay-stack-index, 0) + 100);"
  >
  </div>
  <div
    data-slot="sheet-content"
    data-side={side}
    hidden
    class={cn(sheetContentVariants({ side }), className)}
    style={`z-index: calc(var(--sheet-content-stack-index, 0) + 101);${style ? ` ${style}` : ""}`}
    {...props}
  >
    <slot />
    {
      showCloseButton && (
        <Button
          type="button"
          variant="ghost"
          size="icon-sm"
          class="absolute top-4 right-4"
          data-slot="sheet-close"
          aria-label="Close"
        >
          <XIcon />
          <span class="sr-only">Close</span>
        </Button>
      )
    }
  </div>
</div>
